import anthropic
import base64
from pathlib import Path

def load_image_b64(path: str) -> str:
    return base64.standard_b64encode(Path(path).read_bytes()).decode("utf-8")

client = anthropic.Anthropic()

def multimodal_reasoning_agent(image_path: str, question: str) -> str:
    """Run a single-turn multimodal reasoning query."""
    img_b64 = load_image_b64(image_path)

    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        messages=[
            {
                "role": "user",
                "content": [
                    {
                        "type": "image",
                        "source": {
                            "type": "base64",
                            "media_type": "image/jpeg",
                            "data": img_b64,
                        },
                    },
                    {
                        "type": "text",
                        "text": f"""Analyse the image above carefully before answering.

Question: {question}

Reasoning: Think step by step about what the image shows.
Cite specific visual evidence (e.g., colours, labels, positions, values)
in your reasoning chain before stating your conclusion.
""",
                    },
                ],
            }
        ],
    )
    return response.content[0].text

# Usage
answer = multimodal_reasoning_agent(
    "circuit_board.jpg",
    "Which component is most likely causing the overheating shown by the discolouration?"
)
print(answer)

import anthropic, base64, httpx
from pathlib import Path

client = anthropic.Anthropic()

tools = [
    {
        "name": "fetch_image",
        "description": "Fetch an image from a URL and return it as base64.",
        "input_schema": {
            "type": "object",
            "properties": {
                "url": {"type": "string", "description": "Image URL to fetch"},
                "max_size_kb": {"type": "integer", "default": 2048}
            },
            "required": ["url"]
        }
    },
    {
        "name": "search_academic",
        "description": "Search academic databases for papers matching a query.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string"},
                "max_results": {"type": "integer", "default": 5}
            },
            "required": ["query"]
        }
    }
]

def execute_tool(name: str, inputs: dict) -> str:
    if name == "fetch_image":
        try:
            resp = httpx.get(inputs["url"], timeout=10)
            b64 = base64.standard_b64encode(resp.content).decode()
            return f"image_b64:{b64}"
        except Exception as e:
            return f"Error fetching image: {e}"
    elif name == "search_academic":
        # Stub — in production, call Semantic Scholar or PubMed API
        return f"Found 5 papers on: {inputs['query']}"
    return "Unknown tool"

def multimodal_research_agent(task: str, images: list[str]) -> str:
    """Agent that reasons over images and can fetch additional resources."""

    content = []
    for path in images:
        b64 = base64.standard_b64encode(Path(path).read_bytes()).decode()
        content.append({"type": "image", "source": {"type": "base64", "media_type": "image/jpeg", "data": b64}})
    content.append({"type": "text", "text": task})

    messages = [{"role": "user", "content": content}]

    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text

        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = execute_tool(block.name, block.input)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages.append({"role": "user", "content": tool_results})
        else:
            break

    return "Agent stopped unexpectedly."

# Usage
answer = multimodal_research_agent(
    "Analyse this microscopy image and find related papers.",
    ["cell_sample.jpg"]
)
print(answer)
